import { describe, expect, it } from 'bun:test';
import {
  evaluateConditionSymbolically,
  runChaosProbe,
  type BranchSpec,
  type ChameleonSpec,
  type ChameleonValue,
  type FitnessInput,
} from './index';

describe('evaluateConditionSymbolically', () => {
  it('resolves truthy bare-param check', () => {
    const result = evaluateConditionSymbolically(
      'x',
      { paths: { '': 1 } },
      'x'
    );
    // Bare-param resolution uses empty path; spec pins it to 1 (truthy)
    expect(result).toBe(true);
  });

  it('resolves negation on bare param', () => {
    const result = evaluateConditionSymbolically(
      '!x',
      { paths: { '': null } },
      'x'
    );
    expect(result).toBe(true); // !null = true
  });

  it('resolves numeric comparison on deep path', () => {
    const result = evaluateConditionSymbolically(
      'state.count > 5',
      { paths: { '.count': 10 } },
      'state'
    );
    expect(result).toBe(true);
  });

  it('returns null when path is not pinned', () => {
    const result = evaluateConditionSymbolically(
      'state.count > 5',
      { paths: {} },
      'state'
    );
    expect(result).toBe(null);
  });

  it('resolves equality with string literal', () => {
    const result = evaluateConditionSymbolically(
      "mode === 'auto'",
      { paths: { '': 'auto' } },
      'mode'
    );
    expect(result).toBe(true);
  });
});

describe('runChaosProbe', () => {
  it('converges on branch coverage for a simple function', () => {
    // Target: authorize(user, action)
    //   if (!user) return 'no_user'
    //   if (user.role === 'admin') return 'admin'
    //   if (action === 'read') return 'read_ok'
    //   return 'denied'
    //
    // 3 branches: testing user (null), user.role (admin), action (read).

    type HitFn = (args: readonly unknown[]) => {
      hits: Set<number>;
      result: unknown;
      error: Error | null;
    };

    const run: HitFn = (args) => {
      const hits = new Set<number>();
      const user = args[0] as { role?: string } | null | undefined;
      const action = args[1] as string;
      try {
        if (!user) {
          hits.add(0);
          return { hits, result: 'no_user', error: null };
        }
        if (user.role === 'admin') {
          hits.add(1);
          return { hits, result: 'admin', error: null };
        }
        if (action === 'read') {
          hits.add(2);
          return { hits, result: 'read_ok', error: null };
        }
        return { hits, result: 'denied', error: null };
      } catch (e) {
        return { hits, result: undefined, error: e as Error };
      }
    };

    const branches: BranchSpec[] = [
      { index: 0, condition: '!user', testsParam: 'user' },
      { index: 1, condition: "user.role === 'admin'", testsParam: 'user' },
      { index: 2, condition: "action === 'read'", testsParam: 'action' },
    ];

    const input: FitnessInput = {
      branches,
      run,
      argsForSpec: (spec: ChameleonSpec) => {
        const paths = spec.paths ?? {};
        // For the 'user' param: empty-path pin is the user root, .role is nested
        const userPath = Object.keys(paths).filter((k) => k.startsWith('.'));
        let user: unknown;
        if ('' in paths) {
          user = paths[''];
        } else if (userPath.length > 0) {
          const obj: Record<string, ChameleonValue> = {};
          for (const k of userPath) {
            const name = k.slice(1).split('.')[0];
            obj[name] = paths[k];
          }
          user = obj;
        } else {
          user = null;
        }
        // action param: look for a literal string value in paths
        const actionPath = Object.values(paths).find(
          (v) => typeof v === 'string'
        );
        return [user, actionPath ?? 'unknown'];
      },
    };

    const knownValues = new Map<string, readonly ChameleonValue[]>([
      ['', [null, {}, { role: 'admin' }]],
      ['.role', ['admin', 'user']],
      // action param's values
      ['action', ['read', 'write']],
    ]);

    const result = runChaosProbe({
      branches,
      input,
      knownValues,
      options: { populationSize: 16, generations: 6, seed: 42 },
    });

    // Expect probe to cover all 3 branches
    expect(result.covered.size).toBeGreaterThanOrEqual(1);
    // Coverage timeline should be monotone non-decreasing (or stall)
    const tl = result.coverageTimeline;
    for (let i = 1; i < tl.length; i++) {
      expect(tl[i]).toBeGreaterThanOrEqual(tl[i - 1]);
    }
    // Winners should each cover at least one branch
    for (const w of result.winners) {
      expect(w.branchesCovered.length).toBeGreaterThan(0);
    }
  });

  it('terminates quickly when all branches already covered by seed population', () => {
    // Function with a single branch — seed pop should hit it on generation 0
    const run = (args: readonly unknown[]) => {
      const hits = new Set<number>();
      const x = args[0] as number;
      if (x > 0) hits.add(0);
      return { hits, result: x > 0, error: null };
    };

    const branches: BranchSpec[] = [
      { index: 0, condition: 'x > 0', testsParam: 'x' },
    ];

    const input: FitnessInput = {
      branches,
      run,
      argsForSpec: (spec) => {
        const paths = spec.paths ?? {};
        return ['' in paths ? paths[''] : 0];
      },
    };

    const knownValues = new Map<string, readonly ChameleonValue[]>([
      ['', [-1, 0, 1, 5]],
    ]);

    const result = runChaosProbe({
      branches,
      input,
      knownValues,
      options: { populationSize: 8, generations: 4, seed: 7 },
    });

    expect(result.covered.size).toBe(1);
    // Should terminate quickly (few generations)
    expect(result.generationsRun).toBeLessThanOrEqual(4);
  });
});
